{% extends "base.html" %}
{% load static %}

{% block extra_css %}
<style>
    .analytics-section {
        margin: 20px 0;
    }
    .widget {
        display: inline-block;
        padding: 20px;
        margin: 10px;
        background: #f5f5f5;
        border-radius: 8px;
        min-width: 200px;
    }
    .widget h3 {
        margin: 0 0 10px 0;
        color: #333;
    }
    .metric {
        font-size: 24px;
        font-weight: bold;
        color: #007bff;
    }
</style>
{% endblock %}

{% block content %}
<div class="dashboard">
    <h1>Dashboard</h1>

    <div class="stats">
        <p>Welcome, {{ user.username }}</p>
    </div>

    <!-- Analytics Widgets -->
    <div class="analytics-section">
        <h2>Analytics</h2>
        {% include "dashboard/analytics.html" %}
    </div>

    <!-- Custom Widgets -->
    <div class="widgets-section">
        {% include "dashboard/widgets.html" %}
    </div>
</div>
{% endblock %}
